SELECT 


 ORDER BY e.rprt_yr DESC, e.er_ver DESC, e.frst_reg_dt DESC
 LIMIT #{pageSize} OFFSET #{offset}

SELECT MAX(CAST(SPLIT_PART(er_ver, '.', 1) AS INTEGER)) || '.0'
  FROM er.tn_er
 WHERE oprtr_id = #{oprtrId}
   AND rprt_yr  = #{rprtYr}

